func:
// Transform Modbus register array to SQL params
let values = msg.payload;

// Registers: [temp_x10, humidity_x10, pressure, status]
let temp = (values[0] || 0) / 10;
let humidity = (values[1] || 0) / 10;
let pressure = values[2] || 0;
let status = values[3] || 0;

// Set query and params for postgres-query node
msg.query = "INSERT INTO sensor_readings (temperature, humidity, pressure, status) VALUES ($1, $2, $3, $4)";
msg.queryParams = [temp, humidity, pressure, status];

// Keep original modbus data for debugging
msg.modbus_data = {
    raw: values,
    temperature: temp,
    humidity: humidity,
    pressure: pressure,
    status: status
};

return msg;
